func ysortAttr(on bool) string {
	if on {
		return "true"
	}
	return "false"
}

func ysortChipClass(on bool) string {
	if on {
		return "bx-chip bx-chip--on"
	}
	return "bx-chip bx-chip--ghost"
}

func ysortChipTitle(on bool) string {
	if on {
		return "Y-sort is ON: entities sort by foot position so the player walks behind props correctly. Click to disable."
	}
	return "Y-sort is OFF: entities draw in id order. Click to enable foot-position sorting (the walk-behind illusion)."
}

